//
// AP-066 canonical fix. Three properties work as a unit:
//
//   1. flex-shrink: 0  — the logo never yields space to .links under flex
//                        compression. The browser cannot take width from it.
//   2. white-space: nowrap — the link element itself is declared single-line.
//                        Without this, an inline-flex container can still
//                        "wrap" its children to a second flex row at extreme
//                        squeeze even when flex-shrink is 0, because the
//                        browser re-evaluates the intrinsic content width of
//                        the inline-flex box during reflow.
//   3. flex-wrap: nowrap — keeps the logoMark + logoText on one row regardless
//                        of how narrow the logo's own inline-flex context gets.
//
// None of these three can be removed. flex-shrink alone is not sufficient.
// See AP-066 and FB-146.
.logo {
  display: inline-flex;
  align-items: center;
  flex-wrap: nowrap;       // (3) logoMark + logoText always on one row
  white-space: nowrap;     // (2) the link element itself never line-breaks
